// ── Single budget line row (with building label + live $/SF) ────────────────
function MpBudgetLine({ item, onUpdate, onRemove, totalSF, gcPct, contingencyPct }) {
  const [qty,  setQty]  = useState(String(item.qty||""));
  const [rate, setRate] = useState(String(item.rate||""));
  const [bldg, setBldg] = useState(item.building||"");
  const [desc, setDesc] = useState(item.desc||"");
  useEffect(()=>setQty(String(item.qty||"")),[item.qty]);
  useEffect(()=>setRate(String(item.rate||"")),[item.rate]);
  useEffect(()=>setBldg(item.building||""),[item.building]);
  useEffect(()=>setDesc(item.desc||""),[item.desc]);
  const q = parseFloat(qty)||0;
  const r = parseFloat(rate)||0;
  const lineTotal = q * r;
  // Spread GC + contingency invisibly into each line for $/SF display
  const gcMult  = 1 + (gcPct||0)/100;
  const conMult = 1 + (contingencyPct||0)/100;
  const grossedRate = r * gcMult * conMult;
  const sfRate = totalSF > 0 && item.unit==="SF" ? grossedRate : null;
  const fi = {padding:"5px 7px",border:"1px solid #D4D9EE",borderRadius:5,fontSize:12,fontFamily:"inherit",outline:"none",background:"#fff",width:"100%",boxSizing:"border-box"};
  return (
    <tr style={{borderBottom:"1px solid #F4F6FB"}}>
      <td style={{padding:"4px 6px",width:70}}>
        <input value={bldg} onChange={e=>{setBldg(e.target.value);onUpdate({...item,building:e.target.value});}}
          placeholder="Bldg A" style={{...fi,fontSize:11,fontWeight:600,color:"#8B5CF6",borderColor:"#E8EBF4"}}/>
      </td>
      <td style={{padding:"6px 8px",fontSize:12,color:"#1A2240",fontWeight:500,whiteSpace:"nowrap"}}>{item.label}</td>
      <td style={{padding:"4px 6px",minWidth:120}}>
        <input value={desc} onChange={e=>{setDesc(e.target.value);onUpdate({...item,desc:e.target.value});}} placeholder="Notes…" style={fi}/>
      </td>
      <td style={{padding:"4px 6px",width:50,textAlign:"center",fontSize:11,color:"#9BA3BF"}}>{item.unit}</td>
      <td style={{padding:"4px 6px",width:80}}>
        <input type="number" value={qty} onChange={e=>{setQty(e.target.value);onUpdate({...item,qty:parseFloat(e.target.value)||0});}} placeholder="0" style={{...fi,textAlign:"right"}}/>
      </td>
      <td style={{padding:"4px 6px",width:90}}>
        <input type="number" value={rate} onChange={e=>{setRate(e.target.value);onUpdate({...item,rate:parseFloat(e.target.value)||0});}} placeholder="0.00" style={{...fi,textAlign:"right"}}/>
      </td>
      <td style={{padding:"6px 8px",textAlign:"right",fontSize:13,fontWeight:700,color:lineTotal>0?"#1A2240":"#CBD1E8",whiteSpace:"nowrap"}}>
        {lineTotal>0?"$"+Math.round(lineTotal).toLocaleString():"—"}
      </td>
      <td style={{padding:"6px 8px",textAlign:"right",fontSize:10,color:"#9BA3BF",whiteSpace:"nowrap"}}>
        {sfRate!==null ? <span style={{color:sfRate>0?"#8B5CF6":"#CBD1E8",fontWeight:600}}>${sfRate.toFixed(2)}/SF</span> : "—"}
      </td>
      <td style={{padding:"4px 4px",textAlign:"center",width:28}}>
        <button onClick={onRemove} style={{background:"none",border:"none",color:"#F87171",cursor:"pointer",fontSize:14,padding:0,lineHeight:1}}>✕</button>
      </td>
    </tr>
  );
}

// ── Full budget tool ─────────────────────────────────────────────────────────
function MpBudgetTool({ opp, company, items, setItems, overrides, setOverrides }) {
  const W = {gcPct:10,contingency:5,margin:15,...overrides};
  const setW = (k,v) => setOverrides(p=>({...p,[k]:v}));
  const [showAdd, setShowAdd] = useState(false);

  // SF auto-detect from line items, but adjustable
  const autoSF = items.filter(i=>i.unit==="SF").reduce((s,i)=>s+(i.qty||0),0);
  const [sfOverride, setSfOverride] = useState("");
  const totalSF = parseFloat(sfOverride)||autoSF;

  const direct      = items.reduce((s,i)=>s+(i.qty||0)*(i.rate||0),0);
  const gcAmt       = direct * (W.gcPct/100);
  const contingency = (direct+gcAmt) * (W.contingency/100);
  const subtotal    = direct+gcAmt+contingency;
  const marginAmt   = subtotal * (W.margin/(100-Math.min(W.margin,99)));
  const totalBid    = subtotal+marginAmt;
  const gpm         = totalBid>0 ? marginAmt/totalBid : 0;
  const fmtC = n => "$"+Math.round(n).toLocaleString();
  const pctSty = {width:68,padding:"5px 8px",border:"1.5px solid #CBD1E8",borderRadius:6,fontSize:13,fontFamily:"inherit",outline:"none",textAlign:"right"};

  // Building tiles — clickable to add a duplicate building-type line
  const BLDG_TYPES = TRADE_DEFAULTS.filter(t=>t.isBldg);
  const addTrade = (t, bldgLabel) => {
    setItems(prev=>[...prev,{...t, id:t.id+"-"+Date.now(), qty:0, rate:t.rate, desc:"", building:bldgLabel||""}]);
  };
  const updateItem = (id,u) => setItems(prev=>prev.map(i=>i.id===id?u:i));
  const removeItem = (id)   => setItems(prev=>prev.filter(i=>i.id!==id));

  // Group items by building for visual grouping
  const buildings = [...new Set(items.map(i=>i.building||""))];

  return (
    <div style={{display:"grid",gridTemplateColumns:"1fr 300px",gap:0,flex:1,minHeight:0,overflow:"hidden"}}>
      {/* Left - line items */}
      <div style={{overflowY:"auto",padding:"16px 18px",display:"flex",flexDirection:"column",gap:12}}>

        {/* Building type quick-add tiles */}
        {opp && (
          <div>
            <div style={{fontSize:10,fontWeight:700,color:"#9BA3BF",textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>Add Building / Structure</div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:4}}>
              {BLDG_TYPES.map(t=>(
                <button key={t.id} onClick={()=>{
                  const existing = items.filter(i=>i.id===t.id||i.id.startsWith(t.id+"-"));
                  const letter = String.fromCharCode(65+existing.length); // A, B, C...
                  addTrade(t,"Bldg "+letter);
                }}
                  style={{padding:"6px 14px",borderRadius:20,border:"1.5px solid #CBD1E8",background:"#F9FAFC",color:"#1A2240",fontSize:11,cursor:"pointer",fontFamily:"inherit",fontWeight:600,display:"flex",alignItems:"center",gap:5}}>
                  <span style={{width:8,height:8,borderRadius:"50%",background:"#8B5CF6",display:"inline-block"}}/>
                  {t.label}
                  <span style={{fontSize:9,color:"#9BA3BF"}}>${t.rate}/SF</span>
                </button>
              ))}
              <button onClick={()=>setShowAdd(v=>!v)}
                style={{padding:"6px 14px",borderRadius:20,border:"1.5px solid #3B6FE840",background:"#EEF3FF",color:"#3B6FE8",fontSize:11,cursor:"pointer",fontFamily:"inherit",fontWeight:600}}>
                + Other Trade
              </button>
            </div>
          </div>
        )}

        {/* Other trade picker */}
        {showAdd && (
          <div style={{background:"#fff",borderRadius:10,border:"1px solid #D4D9EE",padding:"12px 14px"}}>
            <div style={{fontSize:10,fontWeight:700,color:"#4A5278",textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>Select trade</div>
            <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
              {TRADE_DEFAULTS.filter(t=>!t.isBldg).map(t=>(
                <button key={t.id} onClick={()=>{addTrade(t,"");setShowAdd(false);}}
                  style={{padding:"4px 10px",borderRadius:5,border:"1px solid #CBD1E8",background:"#F9FAFC",color:"#1A2240",fontSize:11,cursor:"pointer",fontFamily:"inherit"}}>
                  {t.label}
                </button>
              ))}
            </div>
            <button onClick={()=>setShowAdd(false)} style={{marginTop:8,background:"none",border:"none",color:"#9BA3BF",cursor:"pointer",fontSize:11,fontFamily:"inherit"}}>Cancel</button>
          </div>
        )}

        {!opp && (
          <div style={{textAlign:"center",padding:"60px 24px",color:"#9BA3BF",border:"2px dashed #E0E4F0",borderRadius:12}}>
            <div style={{fontSize:36,marginBottom:10}}>📊</div>
            <div style={{fontSize:15,fontWeight:600,color:"#1A2240",marginBottom:6}}>Select a project from the left</div>
            <div style={{fontSize:12}}>Choose any opportunity to start building your estimate</div>
          </div>
        )}

        {opp && items.length===0 && !showAdd && (
          <div style={{textAlign:"center",padding:"40px 24px",color:"#9BA3BF",border:"2px dashed #E0E4F0",borderRadius:10}}>
            <div style={{fontSize:28,marginBottom:8}}>🏗️</div>
            <div style={{fontSize:13,fontWeight:600,color:"#1A2240",marginBottom:4}}>Click a building type above to start</div>
            <div style={{fontSize:11}}>Each click adds a new building (A, B, C…) with its own SF and rate</div>
          </div>
        )}

        {items.length > 0 && (
          <div style={{background:"#fff",borderRadius:10,border:"1px solid #D4D9EE",overflow:"hidden"}}>
            <table style={{width:"100%",borderCollapse:"collapse"}}>
              <thead>
                <tr style={{background:"#F9FAFC",borderBottom:"2px solid #D4D9EE"}}>
                  {["Bldg","Trade","Notes","Unit","SF / Qty","$/Unit","Total","$/SF (w/GC)",""].map((h,i)=>(
                    <th key={i} style={{padding:"6px 8px",fontSize:8,color:"#9BA3BF",textTransform:"uppercase",letterSpacing:"0.07em",textAlign:i>=4&&i<=7?"right":"left",fontWeight:700,whiteSpace:"nowrap"}}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {items.map(item=>(
                  <MpBudgetLine key={item.id} item={item}
                    onUpdate={u=>updateItem(item.id,u)}
                    onRemove={()=>removeItem(item.id)}
                    totalSF={totalSF}
                    gcPct={W.gcPct}
                    contingencyPct={W.contingency}
                  />
                ))}
              </tbody>
              <tfoot>
                <tr style={{background:"#F4F6FB",borderTop:"2px solid #D4D9EE"}}>
                  <td colSpan={6} style={{padding:"7px 8px",fontSize:11,fontWeight:700,color:"#4A5278"}}>Direct Cost Subtotal</td>
                  <td style={{padding:"7px 8px",textAlign:"right",fontSize:14,fontWeight:800,color:"#1A2240"}}>{fmtC(direct)}</td>
                  <td style={{padding:"7px 8px",textAlign:"right",fontSize:10,color:"#9BA3BF"}}>
                    {totalSF>0?<span style={{fontWeight:700,color:"#8B5CF6"}}>${(totalBid/totalSF).toFixed(2)}/SF all-in</span>:""}
                  </td>
                  <td/>
                </tr>
              </tfoot>
            </table>
          </div>
        )}
      </div>

      {/* Right - summary panel */}
      <div style={{background:"#F4F6FB",borderLeft:"1px solid #D4D9EE",overflowY:"auto",padding:"14px 16px",display:"flex",flexDirection:"column",gap:10}}>

        {/* Assumptions - GC & contingency hidden from print, spread into line items */}
        <div style={{background:"#fff",borderRadius:10,border:"1px solid #D4D9EE",padding:"12px 14px"}}>
          <div style={{fontSize:10,fontWeight:700,color:"#4A5278",textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:10}}>Cost Assumptions</div>
          {[
            {label:"GC %", key:"gcPct",      hint:"Spread across line items"},
            {label:"Contingency %", key:"contingency", hint:"Spread across line items"},
            {label:"Margin %", key:"margin", hint:"Target gross profit"},
          ].map(f=>(
            <div key={f.key} style={{display:"flex",alignItems:"center",gap:6,marginBottom:7}}>
              <div style={{flex:1}}>
                <div style={{fontSize:11,fontWeight:600,color:"#1A2240"}}>{f.label}</div>
                <div style={{fontSize:9,color:"#9BA3BF"}}>{f.hint}</div>
              </div>
              <input type="number" value={W[f.key]} onChange={e=>setW(f.key,parseFloat(e.target.value)||0)} style={pctSty}/>
              <span style={{fontSize:11,color:"#4A5278"}}>%</span>
            </div>
          ))}
        </div>

        {/* SF Sanity Check — auto-pulls from SF lines but overrideable */}
        <div style={{background:"#fff",borderRadius:10,border:"1px solid #D4D9EE",padding:"12px 14px"}}>
          <div style={{fontSize:10,fontWeight:700,color:"#4A5278",textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>$/SF Sanity Check</div>
          <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:8}}>
            <input type="number" value={sfOverride||autoSF||""} onChange={e=>setSfOverride(e.target.value)}
              placeholder={autoSF>0?autoSF.toLocaleString()+" SF (auto)":"Total SF"}
              style={{flex:1,padding:"6px 8px",border:"1px solid #CBD1E8",borderRadius:6,fontSize:12,fontFamily:"inherit",outline:"none"}}/>
            <span style={{fontSize:10,color:"#9BA3BF",whiteSpace:"nowrap"}}>SF total</span>
          </div>
          {autoSF>0 && !sfOverride && <div style={{fontSize:9,color:"#9BA3BF",marginBottom:6}}>Auto-detected from SF line items</div>}
          {totalSF>0 && (
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:5}}>
              {[
                {label:"Direct $/SF",value:(direct/totalSF).toFixed(2),color:"#4A5278"},
                {label:"Bid $/SF",   value:(totalBid/totalSF).toFixed(2),color:"#8B5CF6"},
              ].map(r=>(
                <div key={r.label} style={{background:"#F4F6FB",borderRadius:6,padding:"6px 8px",textAlign:"center"}}>
                  <div style={{fontSize:13,fontWeight:800,color:r.color}}>${r.value}</div>
                  <div style={{fontSize:9,color:"#9BA3BF"}}>{r.label}</div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Cost breakdown */}
        <div style={{background:"#fff",borderRadius:10,border:"1px solid #D4D9EE",padding:"12px 14px"}}>
          <div style={{fontSize:10,fontWeight:700,color:"#4A5278",textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>Cost Breakdown</div>
          {[
            {label:"Direct Costs",                       value:direct,      color:"#1A2240",bold:false},
            {label:`+ GC (${W.gcPct}%)`,                 value:gcAmt,       color:"#9BA3BF",indent:true},
            {label:`+ Contingency (${W.contingency}%)`,  value:contingency, color:"#9BA3BF",indent:true},
            {label:"Cost Subtotal",                      value:subtotal,    color:"#1A2240",bold:true},
            {label:`+ Margin (${W.margin}%)`,            value:marginAmt,   color:"#4ADE80"},
          ].map((r,i)=>(
            <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"3px 0",borderTop:r.bold?"1px solid #E0E4F0":"none",marginTop:r.bold?4:0}}>
              <span style={{fontSize:10,color:r.color,fontWeight:r.bold?700:400,paddingLeft:r.indent?10:0}}>{r.label}</span>
              <span style={{fontSize:10,fontWeight:r.bold?800:600,color:r.color}}>{fmtC(r.value)}</span>
            </div>
          ))}
        </div>

        {/* Total bid */}
        <div style={{background:"linear-gradient(135deg,#1A2240,#253260)",borderRadius:12,padding:"14px",color:"#fff"}}>
          <div style={{fontSize:8,color:"rgba(255,255,255,0.5)",textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:4}}>Total Bid Price</div>
          <div style={{fontSize:26,fontWeight:900,letterSpacing:"-0.02em",marginBottom:8}}>{fmtC(totalBid)}</div>
          <div style={{display:"flex",gap:12,paddingTop:8,borderTop:"1px solid rgba(255,255,255,0.15)"}}>
            <div><div style={{fontSize:15,fontWeight:800,color:"#4ADE80"}}>{(gpm*100).toFixed(1)}%</div><div style={{fontSize:7,color:"rgba(255,255,255,0.4)",textTransform:"uppercase"}}>GPM</div></div>
            <div><div style={{fontSize:15,fontWeight:800,color:"#60A5FA"}}>{fmtC(marginAmt)}</div><div style={{fontSize:7,color:"rgba(255,255,255,0.4)",textTransform:"uppercase"}}>Gross Profit</div></div>
          </div>
        </div>

        {/* Per-building summary */}
        {buildings.filter(b=>b).length>0 && (
          <div style={{background:"#fff",borderRadius:10,border:"1px solid #D4D9EE",padding:"12px 14px"}}>
            <div style={{fontSize:10,fontWeight:700,color:"#4A5278",textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:8}}>By Building</div>
            {buildings.filter(b=>b).map(bldg=>{
              const bItems=items.filter(i=>(i.building||"")===(bldg||""));
              const bTotal=bItems.reduce((s,i)=>s+(i.qty||0)*(i.rate||0),0);
              const bSF=bItems.filter(i=>i.unit==="SF").reduce((s,i)=>s+(i.qty||0),0);
              return (
                <div key={bldg} style={{display:"flex",justifyContent:"space-between",padding:"4px 0",borderBottom:"1px solid #F4F6FB"}}>
                  <span style={{fontSize:11,fontWeight:700,color:"#8B5CF6"}}>{bldg}</span>
                  <div style={{textAlign:"right"}}>
                    <div style={{fontSize:11,fontWeight:700,color:"#1A2240"}}>{fmtC(bTotal)}</div>
                    {bSF>0&&<div style={{fontSize:9,color:"#9BA3BF"}}>{bSF.toLocaleString()} SF · ${(bTotal/bSF).toFixed(2)}/SF direct</div>}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}


// ── Vendor Row for bid tracker ───────────────────────────────────────────────
function VendorRow({ v, BID_TRADES, onUpdate, onRemove }) {
  const [editing, setEditing]       = useState(false);
  const [showTrades, setShowTrades] = useState(false);
  const [notes, setNotes]           = useState(v.notes||"");
  const [bidAmt, setBidAmt]         = useState(v.bidAmount||"");

  const STATUS = [
    { key:"infoSent",    label:"Info Sent",  icon:"📧" },
    { key:"bidding",     label:"Bidding",    icon:"✏️" },
    { key:"bidReceived", label:"Bid Rec'd",  icon:"✅" },
  ];

  const toggleStatus = (key) => {
    const newVal = !v[key];
    onUpdate({ [key]: newVal });
  };

  const dot = (on) => ({
    width:14, height:14, borderRadius:"50%",
    background: on ? "#4ADE80" : "#E0E4F0",
    border: on ? "2px solid #4ADE8060" : "2px solid #CBD1E8",
    cursor:"pointer", flexShrink:0,
    display:"inline-block", transition:"all 0.1s"
  });

  const fi = {padding:"4px 7px",border:"1px solid #CBD1E8",borderRadius:5,fontSize:11,fontFamily:"inherit",outline:"none",width:"100%",boxSizing:"border-box"};

  return (
    <div style={{display:"grid",gridTemplateColumns:"240px 120px 140px 80px 80px 80px 100px 1fr 36px",borderBottom:"1px solid #F4F6FB",padding:"7px 14px",gap:8,alignItems:"center"}}
      onMouseEnter={e=>e.currentTarget.style.background="#FAFBFF"}
      onMouseLeave={e=>e.currentTarget.style.background=""}>

      {/* Company / Contact */}
      <div>
        {editing ? (
          <div style={{display:"flex",flexDirection:"column",gap:4}}>
            <input value={v.company} onChange={e=>onUpdate({company:e.target.value})} placeholder="Company" style={fi}/>
            <input value={v.contact||""} onChange={e=>onUpdate({contact:e.target.value})} placeholder="Contact" style={fi}/>
          </div>
        ) : (
          <div>
            <div style={{fontSize:12,fontWeight:700,color:"#1A2240",lineHeight:1.3}}>{v.company||"—"}</div>
            {v.contact && <div style={{fontSize:10,color:"#9BA3BF"}}>{v.contact}</div>}
          </div>
        )}
      </div>

      {/* Bid packages / trades */}
      <div style={{position:"relative"}}>
        <button onClick={()=>setShowTrades(t=>!t)}
          style={{padding:"3px 8px",borderRadius:5,border:"1px solid #CBD1E8",background:"#F9FAFC",fontSize:10,cursor:"pointer",fontFamily:"inherit",width:"100%",textAlign:"left",color:(v.trades||[]).length>0?"#3B6FE8":"#9BA3BF"}}>
          {(v.trades||[]).length>0 ? (v.trades||[]).slice(0,2).join(", ")+(v.trades.length>2?` +${v.trades.length-2}`:"") : "Select…"}
        </button>
        {showTrades && (
          <div style={{position:"absolute",top:"100%",left:0,zIndex:100,background:"#fff",border:"1px solid #D4D9EE",borderRadius:8,boxShadow:"0 4px 20px rgba(0,0,0,0.12)",padding:"8px",width:220,maxHeight:200,overflowY:"auto"}}>
            {BID_TRADES.map(t => {
              const sel = (v.trades||[]).includes(t);
              return (
                <div key={t} onClick={()=>{
                  const cur=v.trades||[];
                  onUpdate({trades:sel?cur.filter(x=>x!==t):[...cur,t]});
                }}
                  style={{padding:"4px 8px",cursor:"pointer",borderRadius:4,background:sel?"#EEF3FF":"transparent",color:sel?"#3B6FE8":"#1A2240",fontSize:11,display:"flex",alignItems:"center",gap:6}}>
                  <span style={{fontSize:12}}>{sel?"☑":"☐"}</span>{t}
                </div>
              );
            })}
            <button onClick={()=>setShowTrades(false)} style={{marginTop:6,width:"100%",padding:"4px",background:"#F0F2F8",border:"none",borderRadius:5,cursor:"pointer",fontSize:11,fontFamily:"inherit",color:"#4A5278"}}>Done</button>
          </div>
        )}
      </div>

      {/* Phone / Email */}
      <div>
        {editing ? (
          <div style={{display:"flex",flexDirection:"column",gap:4}}>
            <input value={v.phone||""} onChange={e=>onUpdate({phone:e.target.value})} placeholder="Phone" style={fi}/>
            <input value={v.email||""} onChange={e=>onUpdate({email:e.target.value})} placeholder="Email" style={fi}/>
          </div>
        ) : (
          <div>
            {v.phone && <div style={{fontSize:10,color:"#4A5278"}}>{v.phone}</div>}
            {v.email && <div style={{fontSize:9,color:"#3B6FE8",wordBreak:"break-all"}}>{v.email}</div>}
          </div>
        )}
      </div>

      {/* Status toggles */}
      {["infoSent","bidding","bidReceived"].map(key=>(
        <div key={key} style={{display:"flex",justifyContent:"center"}}>
          <div onClick={()=>toggleStatus(key)} style={dot(!!v[key])} title={key}/>
        </div>
      ))}

      {/* Bid Amount */}
      <div>
        <input type="number" value={bidAmt}
          onChange={e=>{setBidAmt(e.target.value);onUpdate({bidAmount:e.target.value});}}
          placeholder="$0"
          style={{...fi,textAlign:"right",background:v.bidReceived?"#F0FDF4":"#F9FAFC",border:"1px solid "+(v.bidReceived?"#4ADE8050":"#D4D9EE")}}/>
      </div>

      {/* Notes */}
      <div>
        <input value={notes}
          onChange={e=>{setNotes(e.target.value);onUpdate({notes:e.target.value});}}
          placeholder="Notes…"
          style={{...fi,fontSize:10}}/>
      </div>

      {/* Remove */}
      <div style={{display:"flex",gap:4}}>
        <button onClick={()=>setEditing(e=>!e)}
          style={{background:"none",border:"none",color:editing?"#3B6FE8":"#CBD1E8",cursor:"pointer",fontSize:12,padding:"2px"}}>✎</button>
        <button onClick={onRemove}
          style={{background:"none",border:"none",color:"#F87171",cursor:"pointer",fontSize:12,padding:"2px"}}>✕</button>
      </div>
    </div>
  );
}

// -- WBS Row component --
// -- WBS Row component --
function WbsRow({ item, BID_TRADES, onUpdate, onRemove, onAddSub, critical }) {
  const [code, setCode]   = useState(item.code||"");
  const [desc, setDesc]   = useState(item.description||"");
  const [qty,  setQty]    = useState(String(item.qty||""));
  const [rate, setRate]   = useState(String(item.rate||""));
  const [showTrade, setShowTrade] = useState(false);
  const [showSubs, setShowSubs]   = useState(false);
  const total = (parseFloat(qty)||0)*(parseFloat(rate)||0);
  const subTotal = (item.subItems||[]).reduce((s,i)=>(s+(i.qty||0)*(i.rate||0)),0);
  const fi = {padding:"3px 6px",border:"1px solid #D4D9EE",borderRadius:4,fontSize:11,fontFamily:"inherit",outline:"none",width:"100%",boxSizing:"border-box"};

  return (
    <>
      <div style={{display:"grid",gridTemplateColumns:"80px 1fr 130px 55px 80px 90px 90px 50px 28px",borderBottom:"1px solid #F4F6FB",padding:"4px 8px",gap:6,alignItems:"center",background:item.critical?"#FFFBEB":"#fff"}}
        onMouseEnter={e=>e.currentTarget.style.background=item.critical?"#FFF3C4":"#FAFBFF"}
        onMouseLeave={e=>e.currentTarget.style.background=item.critical?"#FFFBEB":"#fff"}>
        <td style={{display:"contents"}}>
          <input value={code} onChange={e=>{setCode(e.target.value);onUpdate({code:e.target.value});}} placeholder="03-100"
            style={{...fi,fontFamily:"monospace",fontSize:10}}/>
        </td>
        <div style={{display:"flex",alignItems:"center",gap:4}}>
          <input value={desc} onChange={e=>{setDesc(e.target.value);onUpdate({description:e.target.value});}} placeholder="Description..."
            style={{...fi,flex:1}}/>
          {(item.subItems||[]).length>0 && (
            <button onClick={()=>setShowSubs(s=>!s)} style={{padding:"1px 5px",background:"#EEF3FF",border:"none",borderRadius:3,color:"#3B6FE8",fontSize:9,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>
              {showSubs?"hide":"+"+item.subItems.length}
            </button>
          )}
        </div>
        <div style={{position:"relative"}}>
          <button onClick={()=>setShowTrade(t=>!t)}
            style={{...fi,textAlign:"left",cursor:"pointer",background:"#F9FAFC",color:item.trade?"#1A2240":"#9BA3BF",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",fontSize:10}}>
            {item.trade||"Select trade..."}
          </button>
          {showTrade && (
            <div style={{position:"absolute",top:"100%",left:0,zIndex:100,background:"#fff",border:"1px solid #D4D9EE",borderRadius:8,boxShadow:"0 4px 20px rgba(0,0,0,0.12)",padding:"4px",width:190,maxHeight:160,overflowY:"auto"}}>
              {BID_TRADES.map(t=>(
                <div key={t} onClick={()=>{onUpdate({trade:t});setShowTrade(false);}}
                  style={{padding:"3px 8px",cursor:"pointer",borderRadius:3,background:item.trade===t?"#EEF3FF":"transparent",color:item.trade===t?"#3B6FE8":"#1A2240",fontSize:11}}>
                  {t}
                </div>
              ))}
            </div>
          )}
        </div>
        <select value={item.unit||"LS"} onChange={e=>onUpdate({unit:e.target.value})} style={{...fi,fontSize:10}}>
          {["LS","SF","LF","SY","CY","EA","TON","SQ","HD","MO","HR"].map(u=><option key={u}>{u}</option>)}
        </select>
        <input type="number" value={qty} onChange={e=>{setQty(e.target.value);onUpdate({qty:parseFloat(e.target.value)||0});}} placeholder="0" style={{...fi,textAlign:"right"}}/>
        <input type="number" value={rate} onChange={e=>{setRate(e.target.value);onUpdate({rate:parseFloat(e.target.value)||0});}} placeholder="0.00" style={{...fi,textAlign:"right"}}/>
        <div style={{textAlign:"right",fontSize:11,fontWeight:700,color:(total+subTotal)>0?"#1A2240":"#CBD1E8"}}>
          {(total+subTotal)>0?"$"+Math.round(total+subTotal).toLocaleString():"--"}
        </div>
        {/* Critical toggle */}
        <div style={{display:"flex",justifyContent:"center"}}>
          <div onClick={()=>onUpdate({critical:!item.critical})}
            title={item.critical?"Critical - click to unmark":"Mark as critical"}
            style={{width:14,height:14,borderRadius:"50%",background:item.critical?"#F59E0B":"#E0E4F0",border:item.critical?"2px solid #D97706":"2px solid #CBD1E8",cursor:"pointer",transition:"all 0.1s"}}/>
        </div>
        <button onClick={onRemove} style={{background:"none",border:"none",color:"#F87171",cursor:"pointer",fontSize:13,padding:0,lineHeight:1}}>x</button>
      </div>
      {/* Sub-items */}
      {showSubs && (item.subItems||[]).map((sub,si)=>(
        <div key={sub.id} style={{display:"grid",gridTemplateColumns:"80px 1fr 130px 55px 80px 90px 90px 50px 28px",borderBottom:"1px solid #F4F6FB",padding:"3px 8px 3px 24px",gap:6,alignItems:"center",background:"#F9FBFF"}}>
          <input value={sub.code||""} onChange={e=>onUpdate({subItems:(item.subItems||[]).map((x,j)=>j===si?{...x,code:e.target.value}:x)})}
            placeholder={item.code+"."+( si+1)} style={{...fi,fontFamily:"monospace",fontSize:10,background:"#F4F6FB"}}/>
          <input value={sub.description||""} onChange={e=>onUpdate({subItems:(item.subItems||[]).map((x,j)=>j===si?{...x,description:e.target.value}:x)})}
            placeholder="Sub-item..." style={{...fi,background:"#F4F6FB"}}/>
          <div style={{fontSize:10,color:"#9BA3BF",paddingLeft:4}}>{item.trade}</div>
          <select value={sub.unit||item.unit||"LS"} onChange={e=>onUpdate({subItems:(item.subItems||[]).map((x,j)=>j===si?{...x,unit:e.target.value}:x)})}
            style={{...fi,fontSize:10,background:"#F4F6FB"}}>
            {["LS","SF","LF","SY","CY","EA","TON","SQ","HD","MO","HR"].map(u=><option key={u}>{u}</option>)}
          </select>
          <input type="number" value={sub.qty||""} onChange={e=>onUpdate({subItems:(item.subItems||[]).map((x,j)=>j===si?{...x,qty:parseFloat(e.target.value)||0}:x)})}
            placeholder="0" style={{...fi,textAlign:"right",background:"#F4F6FB"}}/>
          <input type="number" value={sub.rate||""} onChange={e=>onUpdate({subItems:(item.subItems||[]).map((x,j)=>j===si?{...x,rate:parseFloat(e.target.value)||0}:x)})}
            placeholder="0.00" style={{...fi,textAlign:"right",background:"#F4F6FB"}}/>
          <div style={{textAlign:"right",fontSize:11,fontWeight:600,color:(sub.qty||0)*(sub.rate||0)>0?"#4A5278":"#CBD1E8"}}>
            {(sub.qty||0)*(sub.rate||0)>0?"$"+Math.round((sub.qty||0)*(sub.rate||0)).toLocaleString():"--"}
          </div>
          <div/>
          <button onClick={()=>onUpdate({subItems:(item.subItems||[]).filter((_,j)=>j!==si)})}
            style={{background:"none",border:"none",color:"#F87171",cursor:"pointer",fontSize:12,padding:0}}>x</button>
        </div>
      ))}
      {/* Add sub-item row */}
      {showSubs && (
        <div style={{padding:"4px 8px 4px 24px",borderBottom:"1px solid #F0F2F8"}}>
          <button onClick={onAddSub} style={{padding:"2px 8px",background:"#EEF3FF",border:"1px dashed #3B6FE850",borderRadius:4,color:"#3B6FE8",fontSize:10,cursor:"pointer",fontFamily:"inherit"}}>+ Add Sub-item</button>
          <button onClick={()=>setShowSubs(false)} style={{marginLeft:6,padding:"2px 8px",background:"none",border:"none",color:"#9BA3BF",fontSize:10,cursor:"pointer",fontFamily:"inherit"}}>hide</button>
        </div>
      )}
      {!showSubs && (
        <div style={{padding:"2px 8px 2px 24px",borderBottom:"1px solid #F4F6FB"}}>
          <button onClick={()=>{setShowSubs(true);if((item.subItems||[]).length===0)onAddSub();}}
            style={{padding:"1px 6px",background:"none",border:"none",color:"#CBD1E8",fontSize:9,cursor:"pointer",fontFamily:"inherit"}}>+ sub-item</button>
        </div>
      )}
    </>
  );
}



// ── VendorsPage ─────────────────────────────────────────────────────────────
const VENDOR_TABS       = ["All", "MP", "FM", "CapEx", "Lawn", "Snow"];
const VENDOR_CATEGORIES = ["MP", "FM", "CapEx", "Lawn", "Snow"];

const VCAT_STYLE = {
  MP:    { active: { background:"#1e3a5f", color:"#60a5fa", border:"1px solid #2d5a8f" }, inactive: { background:"#f4f6fb", color:"#9ba3bf", border:"1px solid #d4d9ee" } },
  FM:    { active: { background:"#14532d", color:"#4ade80", border:"1px solid #166534" }, inactive: { background:"#f4f6fb", color:"#9ba3bf", border:"1px solid #d4d9ee" } },
  CapEx: { active: { background:"#4a1942", color:"#f0abfc", border:"1px solid #701a75" }, inactive: { background:"#f4f6fb", color:"#9ba3bf", border:"1px solid #d4d9ee" } },
  Lawn:  { active: { background:"#14532d", color:"#86efac", border:"1px solid #15803d" }, inactive: { background:"#f4f6fb", color:"#9ba3bf", border:"1px solid #d4d9ee" } },
  Snow:  { active: { background:"#1e3a5f", color:"#bae6fd", border:"1px solid #0369a1" }, inactive: { background:"#f4f6fb", color:"#9ba3bf", border:"1px solid #d4d9ee" } },
};

const VEMPTY_FORM = {
  vendor_name:"", company_name:"", street_address:"",
  city:"", state:"", country:"USA", zip:"",
  phone:"", email:"", trade:"", notes:"", categories:[],
};

function VendorsPage({ supa }) {
  const [vendors,      setVendors]      = useState([]);
  const [loading,      setLoading]      = useState(true);
  const [activeTab,    setActiveTab]    = useState("All");
  const [search,       setSearch]       = useState("");
  const [tradeFilter,  setTradeFilter]  = useState("All");
  const [selected,     setSelected]     = useState(null);
  const [saving,       setSaving]       = useState(false);
  const [showAdd,      setShowAdd]      = useState(false);
  const [form,         setForm]         = useState(VEMPTY_FORM);
  const [addSaving,    setAddSaving]    = useState(false);
  const [editNotes,    setEditNotes]    = useState(false);
  const [notesValue,   setNotesValue]   = useState("");

  const load = useCallback(async () => {
    setLoading(true);
    const { data } = await supa.from("vendors").select("*").order("vendor_name");
    setVendors(Array.isArray(data) ? data : []);
    setLoading(false);
  }, [supa]);

  useEffect(() => { load(); }, [load]);

  const toggleCat = async (vendor, cat, e) => {
    e && e.stopPropagation();
    const current = vendor.categories || [];
    const updated = current.includes(cat) ? current.filter(c => c !== cat) : [...current, cat];
    setSaving(vendor.id);
    await supa.from("vendors").update({ categories: updated }).eq("id", vendor.id);
    const patch = v => v.id === vendor.id ? { ...v, categories: updated } : v;
    setVendors(vs => vs.map(patch));
    setSelected(s => s?.id === vendor.id ? { ...s, categories: updated } : s);
    setSaving(false);
  };

  const saveNotes = async () => {
    if (!selected) return;
    await supa.from("vendors").update({ notes: notesValue }).eq("id", selected.id);
    setVendors(vs => vs.map(v => v.id === selected.id ? { ...v, notes: notesValue } : v));
    setSelected(s => ({ ...s, notes: notesValue }));
    setEditNotes(false);
  };

  const addVendor = async () => {
    if (!form.vendor_name.trim()) return;
    setAddSaving(true);
    const { data } = await supa.from("vendors").insert(form).select("*");
    if (data && data[0]) {
      setVendors(vs => [...vs, data[0]].sort((a,b)=>(a.vendor_name||"").localeCompare(b.vendor_name||"")));
      setSelected(data[0]);
    }
    setShowAdd(false); setForm(VEMPTY_FORM); setAddSaving(false);
  };

  const trades = ["All", ...Array.from(new Set(vendors.map(v=>v.trade).filter(Boolean))).sort()];
  const tabCounts = Object.fromEntries(VENDOR_CATEGORIES.map(cat=>[cat, vendors.filter(v=>(v.categories||[]).includes(cat)).length]));
  const filtered = vendors.filter(v => {
    if (activeTab !== "All" && !(v.categories||[]).includes(activeTab)) return false;
    if (tradeFilter !== "All" && v.trade !== tradeFilter) return false;
    if (search) {
      const q = search.toLowerCase();
      return (v.vendor_name||"").toLowerCase().includes(q) || (v.company_name||"").toLowerCase().includes(q) ||
             (v.trade||"").toLowerCase().includes(q) || (v.city||"").toLowerCase().includes(q) ||
             (v.email||"").toLowerCase().includes(q) || (v.phone||"").toLowerCase().includes(q);
    }
    return true;
  });

  return (
    <div className="fade-in" style={{ display:"flex", flexDirection:"column", height:"calc(100vh - 80px)", background:"#F4F6FB", borderRadius:14, overflow:"hidden", border:"1px solid #D4D9EE" }}>

      {/* Header */}
      <div style={{ background:"#fff", padding:"18px 24px 0", borderBottom:"1px solid #ECEEF8", flexShrink:0 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:14 }}>
          <div>
            <div style={{ fontSize:22, fontWeight:700, color:"#1A2240", letterSpacing:"-0.01em", textTransform:"uppercase" }}>Vendors</div>
            <div style={{ fontSize:11, color:"#4A5278", marginTop:3, letterSpacing:"0.06em" }}>{filtered.length.toLocaleString()} OF {vendors.length.toLocaleString()} VENDORS</div>
          </div>
          <button className="btn-primary" onClick={() => setShowAdd(true)}>+ Add Vendor</button>
        </div>
        {/* Tabs */}
        <div style={{ display:"flex", gap:2 }}>
          {VENDOR_TABS.map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)}
              style={{ padding:"8px 16px", border:"none", borderRadius:"6px 6px 0 0", cursor:"pointer", fontSize:12, fontWeight:600,
                background: activeTab===tab ? "#F4F6FB" : "transparent",
                color: activeTab===tab ? "#3B6FE8" : "#4A5278",
                borderBottom: activeTab===tab ? "2px solid #3B6FE8" : "2px solid transparent" }}>
              {tab}
              {tab !== "All" && (
                <span style={{ marginLeft:5, background:"#EEF2FF", color:"#3B6FE8", borderRadius:10, padding:"1px 6px", fontSize:10, fontWeight:700 }}>
                  {tabCounts[tab]||0}
                </span>
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Toolbar */}
      <div style={{ display:"flex", gap:10, padding:"12px 24px", background:"#fff", borderBottom:"1px solid #ECEEF8", flexShrink:0 }}>
        <input placeholder="Search vendors, trade, city, email..." value={search} onChange={e=>setSearch(e.target.value)}
          style={{ flex:1, background:"#F4F6FB", border:"1px solid #D4D9EE", borderRadius:8, color:"#1A2240", padding:"8px 12px", fontSize:13, outline:"none" }}/>
        <select value={tradeFilter} onChange={e=>setTradeFilter(e.target.value)}
          style={{ background:"#F4F6FB", border:"1px solid #D4D9EE", borderRadius:8, color:"#1A2240", padding:"8px 12px", fontSize:13, outline:"none", minWidth:170 }}>
          {trades.map(t => <option key={t} value={t}>{t==="All" ? "All Trades" : t}</option>)}
        </select>
      </div>

      {/* Table */}
      <div style={{ flex:1, overflowY:"auto", background:"#fff" }}>
        {loading ? (
          <div style={{ textAlign:"center", padding:80, color:"#9BA3BF", fontSize:14 }}>Loading vendors…</div>
        ) : (
          <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
            <thead>
              <tr style={{ borderBottom:"1px solid #ECEEF8" }}>
                {["Vendor","Trade","Location","Phone","Email","Categories"].map(h => (
                  <th key={h} style={{ padding:"10px 16px", textAlign:"left", color:"#4A5278", fontWeight:600, fontSize:10, textTransform:"uppercase", letterSpacing:"0.07em", background:"#fff", position:"sticky", top:0, zIndex:2, borderBottom:"1px solid #ECEEF8" }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map(v => {
                const isSel = selected?.id === v.id;
                return (
                  <tr key={v.id}
                    onClick={() => { setSelected(v); setEditNotes(false); setNotesValue(v.notes||""); }}
                    style={{ borderBottom:"1px solid #F4F6FB", cursor:"pointer", background: isSel ? "#EEF2FF" : "transparent" }}
                    onMouseEnter={e => { if (!isSel) e.currentTarget.style.background="#F8F9FE"; }}
                    onMouseLeave={e => { if (!isSel) e.currentTarget.style.background="transparent"; }}>
                    <td style={{ padding:"10px 16px", fontWeight:600, color:"#1A2240", maxWidth:220 }}>
                      <div style={{ overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{v.vendor_name||"—"}</div>
                    </td>
                    <td style={{ padding:"10px 16px" }}>
                      {v.trade && <span style={{ background:"#EEF2FF", color:"#3B6FE8", borderRadius:4, padding:"2px 8px", fontSize:11, fontWeight:600, whiteSpace:"nowrap" }}>{v.trade}</span>}
                    </td>
                    <td style={{ padding:"10px 16px", color:"#4A5278", fontSize:12, whiteSpace:"nowrap" }}>
                      {[v.city,v.state].filter(Boolean).join(", ")||"—"}
                    </td>
                    <td style={{ padding:"10px 16px", color:"#4A5278", fontSize:12 }}>{v.phone||"—"}</td>
                    <td style={{ padding:"10px 16px", fontSize:12, maxWidth:200 }}>
                      {v.email ? <a href={"mailto:"+v.email} style={{ color:"#3B6FE8", textDecoration:"none" }} onClick={e=>e.stopPropagation()}>{v.email}</a> : <span style={{color:"#CBD1E8"}}>—</span>}
                    </td>
                    <td style={{ padding:"10px 16px", minWidth:230 }}>
                      <div style={{ display:"flex", gap:4, flexWrap:"wrap", alignItems:"center" }}>
                        {VENDOR_CATEGORIES.map(cat => {
                          const active = (v.categories||[]).includes(cat);
                          return (
                            <button key={cat} onClick={e=>toggleCat(v,cat,e)} disabled={saving===v.id}
                              style={{ padding:"2px 8px", borderRadius:4, fontSize:10, fontWeight:700, cursor:"pointer",
                                ...(active ? VCAT_STYLE[cat].active : VCAT_STYLE[cat].inactive) }}>
                              {cat}
                            </button>
                          );
                        })}
                        {saving===v.id && <span style={{fontSize:10,color:"#3B6FE8",marginLeft:2}}>saving…</span>}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
        {!loading && filtered.length===0 && (
          <div style={{ textAlign:"center", padding:80, color:"#9BA3BF" }}>No vendors match your filters.</div>
        )}
      </div>

      {/* Detail Drawer */}
      {selected && (
        <div style={{ position:"fixed", right:0, top:0, bottom:0, width:360, background:"#fff", borderLeft:"1px solid #D4D9EE", zIndex:100, display:"flex", flexDirection:"column", boxShadow:"-4px 0 24px rgba(0,0,0,0.08)" }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", padding:"20px 20px 0" }}>
            <div style={{ flex:1, paddingRight:12 }}>
              <div style={{ fontSize:15, fontWeight:700, color:"#1A2240", lineHeight:1.3 }}>{selected.vendor_name}</div>
              {selected.company_name && selected.company_name!==selected.vendor_name && (
                <div style={{ fontSize:12, color:"#4A5278", marginTop:3 }}>{selected.company_name}</div>
              )}
            </div>
            <button className="btn-ghost" style={{ fontSize:18, padding:"2px 6px" }} onClick={()=>setSelected(null)}>×</button>
          </div>
          <div style={{ flex:1, overflowY:"auto", padding:"16px 20px 24px" }}>
            {selected.trade && (
              <span style={{ background:"#EEF2FF", color:"#3B6FE8", borderRadius:4, padding:"3px 10px", fontSize:12, fontWeight:600 }}>{selected.trade}</span>
            )}
            {/* Categories */}
            <div style={{ margin:"16px 0 8px", fontSize:10, fontWeight:700, color:"#4A5278", textTransform:"uppercase", letterSpacing:"0.07em" }}>
              Categories {saving===selected.id && <span style={{color:"#3B6FE8",marginLeft:6}}>saving…</span>}
            </div>
            <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
              {VENDOR_CATEGORIES.map(cat => {
                const active = (selected.categories||[]).includes(cat);
                return (
                  <button key={cat} onClick={e=>toggleCat(selected,cat,e)}
                    style={{ padding:"5px 14px", borderRadius:6, fontSize:12, fontWeight:700, cursor:"pointer",
                      ...(active ? VCAT_STYLE[cat].active : VCAT_STYLE[cat].inactive) }}>
                    {active ? "✓ " : ""}{cat}
                  </button>
                );
              })}
            </div>
            <hr style={{ border:"none", borderTop:"1px solid #ECEEF8", margin:"16px 0" }}/>
            {/* Contact details */}
            <div style={{ fontSize:10, fontWeight:700, color:"#4A5278", textTransform:"uppercase", letterSpacing:"0.07em", marginBottom:10 }}>Contact Details</div>
            {[
              { label:"Address", value:[selected.street_address,selected.city,selected.state,selected.zip].filter(Boolean).join(", ") },
              { label:"Phone",   value:selected.phone, href:`tel:${selected.phone}` },
              { label:"Email",   value:selected.email, href:`mailto:${selected.email}` },
            ].map(({ label, value, href }) => !value ? null : (
              <div key={label} style={{ marginBottom:12 }}>
                <div style={{ fontSize:10, color:"#9BA3BF", textTransform:"uppercase", marginBottom:2 }}>{label}</div>
                {href ? <a href={href} style={{ color:"#3B6FE8", fontSize:13, textDecoration:"none" }}>{value}</a>
                      : <div style={{ fontSize:13, color:"#1A2240" }}>{value}</div>}
              </div>
            ))}
            <hr style={{ border:"none", borderTop:"1px solid #ECEEF8", margin:"16px 0" }}/>
            {/* Notes */}
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
              <div style={{ fontSize:10, fontWeight:700, color:"#4A5278", textTransform:"uppercase", letterSpacing:"0.07em" }}>Notes</div>
              {!editNotes && <button className="btn-ghost" style={{fontSize:11}} onClick={()=>{setEditNotes(true);setNotesValue(selected.notes||"");}}>{selected.notes?"Edit":"+ Add"}</button>}
            </div>
            {editNotes ? (
              <div>
                <textarea value={notesValue} onChange={e=>setNotesValue(e.target.value)}
                  style={{ width:"100%", background:"#F4F6FB", border:"1px solid #D4D9EE", borderRadius:8, color:"#1A2240", padding:"8px 10px", fontSize:12, outline:"none", resize:"vertical", minHeight:80, fontFamily:"inherit", boxSizing:"border-box" }}
                  placeholder="Add notes…" autoFocus/>
                <div style={{ display:"flex", gap:8, marginTop:6 }}>
                  <button className="btn-primary" style={{fontSize:12,padding:"5px 14px"}} onClick={saveNotes}>Save</button>
                  <button className="btn-ghost" style={{fontSize:12}} onClick={()=>setEditNotes(false)}>Cancel</button>
                </div>
              </div>
            ) : (
              <div style={{ fontSize:12, color:selected.notes?"#4A5278":"#CBD1E8", fontStyle:selected.notes?"normal":"italic" }}>
                {selected.notes||"No notes yet."}
              </div>
            )}
          </div>
        </div>
      )}

      {/* Add Vendor Modal */}
      {showAdd && (
        <div style={{ position:"fixed", inset:0, background:"rgba(26,34,64,0.45)", zIndex:200, display:"flex", alignItems:"center", justifyContent:"center" }}
          onClick={e=>{ if(e.target===e.currentTarget){setShowAdd(false);setForm(VEMPTY_FORM);} }}>
          <div style={{ background:"#fff", borderRadius:14, border:"1px solid #D4D9EE", padding:28, width:480, maxHeight:"88vh", overflowY:"auto", boxShadow:"0 8px 40px rgba(0,0,0,0.18)" }}>
            <div style={{ fontSize:16, fontWeight:700, color:"#1A2240", marginBottom:20 }}>Add Vendor</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"12px 16px" }}>
              {[
                { key:"vendor_name",    label:"Vendor Name *", full:true },
                { key:"company_name",   label:"Company Name",  full:true },
                { key:"trade",          label:"Trade",         full:false },
                { key:"phone",          label:"Phone",         full:false },
                { key:"email",          label:"Email",         full:true },
                { key:"street_address", label:"Street Address",full:true },
                { key:"city",           label:"City",          full:false },
                { key:"state",          label:"State",         full:false },
                { key:"zip",            label:"Zip",           full:false },
                { key:"country",        label:"Country",       full:false },
              ].map(({ key, label, full }) => (
                <div key={key} style={{ gridColumn: full?"1 / -1":"auto" }}>
                  <label style={{ display:"block", fontSize:11, color:"#4A5278", marginBottom:4, textTransform:"uppercase", letterSpacing:"0.04em" }}>{label}</label>
                  <input value={form[key]} onChange={e=>setForm(f=>({...f,[key]:e.target.value}))} autoComplete="off"
                    style={{ width:"100%", background:"#F4F6FB", border:"1px solid #D4D9EE", borderRadius:8, color:"#1A2240", padding:"8px 10px", fontSize:13, outline:"none", boxSizing:"border-box" }}/>
                </div>
              ))}
            </div>
            <div style={{ marginTop:16 }}>
              <div style={{ fontSize:11, color:"#4A5278", marginBottom:6, textTransform:"uppercase", letterSpacing:"0.04em" }}>Categories</div>
              <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                {VENDOR_CATEGORIES.map(cat => {
                  const active = form.categories.includes(cat);
                  return (
                    <button key={cat} onClick={()=>setForm(f=>({ ...f, categories: active ? f.categories.filter(c=>c!==cat) : [...f.categories,cat] }))}
                      style={{ padding:"5px 14px", borderRadius:6, fontSize:12, fontWeight:700, cursor:"pointer",
                        ...(active ? VCAT_STYLE[cat].active : VCAT_STYLE[cat].inactive) }}>
                      {active?"✓ ":""}{cat}
                    </button>
                  );
                })}
              </div>
            </div>
            <div style={{ marginTop:16 }}>
              <label style={{ display:"block", fontSize:11, color:"#4A5278", marginBottom:4, textTransform:"uppercase" }}>Notes</label>
              <textarea value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}
                style={{ width:"100%", background:"#F4F6FB", border:"1px solid #D4D9EE", borderRadius:8, color:"#1A2240", padding:"8px 10px", fontSize:13, outline:"none", resize:"vertical", minHeight:60, fontFamily:"inherit", boxSizing:"border-box" }}
                placeholder="Optional notes…"/>
            </div>
            <div style={{ display:"flex", gap:10, justifyContent:"flex-end", marginTop:20 }}>
              <button className="btn-ghost" onClick={()=>{setShowAdd(false);setForm(VEMPTY_FORM);}}>Cancel</button>
              <button className="btn-primary" disabled={!form.vendor_name.trim()||addSaving} onClick={addVendor}
                style={{ opacity: form.vendor_name.trim()?1:0.4 }}>
                {addSaving ? "Saving…" : "Add Vendor"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
