  const [subGeocodeProgress,setSubGeocodeProgress]= useState(null);

  // ── Auto-save estimate data to Supabase whenever it changes ──
  const saveEstimateData = useCallback((oppId, wbs, bids, phase) => {
    if (!oppId) return;
    try {
      const estimateBlob = JSON.stringify({ wbs, bids, phase, savedAt: new Date().toISOString() });
      fetch(`${SUPA_URL}/rest/v1/mp_estimates?opp_id=eq.${encodeURIComponent(oppId)}`, {
        method: "GET",
        headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
      }).then(r => r.json()).then(rows => {
        if (rows && rows.length > 0) {
          // Update existing
          fetch(`${SUPA_URL}/rest/v1/mp_estimates?opp_id=eq.${encodeURIComponent(oppId)}`, {
            method: "PATCH",
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`, "Content-Type": "application/json", Prefer: "return=minimal" },
            body: JSON.stringify({ wbs_data: estimateBlob, updated_at: new Date().toISOString() })
          });
        } else {
          // Insert new
          fetch(`${SUPA_URL}/rest/v1/mp_estimates`, {
            method: "POST",
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`, "Content-Type": "application/json", Prefer: "return=minimal" },
            body: JSON.stringify({ opp_id: oppId, wbs_data: estimateBlob, created_at: new Date().toISOString(), updated_at: new Date().toISOString() })
          });
        }
      });
    } catch(e) {}
  }, []);

  const navItems = NAV_ITEMS[activeBU] || NAV_ITEMS.all;
  const buColor  = BU_COLORS[activeBU];

  const handleBUChange = (id) => { setActiveBU(id); setActiveNav("dashboard"); setSelectedCoord(null); setCrmTagFilter(null); setSelectedCustomer(null); };

  // Punch list
  const dynamicPunchList = useMemo(() => {
    const items = [...PUNCH_LIST_STATIC];
    const today = new Date(); today.setHours(0,0,0,0);
    const soon  = new Date(today.getTime() + 7 * 86400000);
    const urgent = new Date(today.getTime() + 2 * 86400000);
    pipeline.forEach(o => {
      if (o.budgetDueDate) {
        const d = new Date(o.budgetDueDate);
        if (d >= today && d <= soon) items.push({ id: "budget-" + o.id, text: "Budget due: " + o.name, bu: o.bu, priority: d <= urgent ? "high" : "medium", dueDate: o.budgetDueDate, tag: "BUDGET DUE" });
      }
      if (o.bidDueDate) {
        const d = new Date(o.bidDueDate);
        if (d >= today && d <= soon) items.push({ id: "bid-" + o.id, text: "Bid due: " + o.name, bu: o.bu, priority: d <= urgent ? "high" : "medium", dueDate: o.bidDueDate, tag: "BID DUE" });
      }
      (o.nextSteps || []).forEach((ns, i) => {
        if (ns.dueDate) {
          const d = new Date(ns.dueDate);
          if (d >= today && d <= soon) items.push({ id: "ns-" + o.id + "-" + i, text: ns.step + ": " + o.name, bu: o.bu, priority: d <= urgent ? "high" : "medium", dueDate: ns.dueDate, tag: ns.step.toUpperCase() });
        }
      });
    });
    // FM: owner_approval follow-up reminders (hit PM's list)
    fmJobs.forEach(j => {
      if (j.stage === "owner_approval" && j.followUpDate) {
        const d = new Date(j.followUpDate + "T12:00:00");
        const overdue = d < today;
        const pmName = j.pm || j.coordinator || "";
        if (overdue || d <= soon) {
          items.push({
            id: "followup-" + j.id,
            text: "Follow up on proposal: " + j.name + (pmName ? " (" + pmName + ")" : ""),
            bu: "facility", priority: overdue || d <= urgent ? "high" : "medium",
            dueDate: j.followUpDate, tag: "FOLLOW-UP", fmJobId: j.id
          });
        }
      }
      // 2-day reminder before scheduled work date
      if (j.stage === "do_work" && j.scheduledDate && !j.subInvoiceSubmitted) {
        const d = new Date(j.scheduledDate + "T12:00:00");
        const twoDaysBefore = new Date(d.getTime() - 2*86400000);
        if (today >= twoDaysBefore && today <= d) {
          items.push({
            id: "sched-" + j.id,
            text: "Work scheduled in 2 days: " + j.name,
            bu: "facility", priority: "high",
            dueDate: j.scheduledDate, tag: "SCHEDULED", fmJobId: j.id
          });
        }
      }
    });
    return items.sort((a, b) => {
      if (!a.dueDate && !b.dueDate) return 0;
      if (!a.dueDate) return 1;
      if (!b.dueDate) return -1;
      return new Date(a.dueDate) - new Date(b.dueDate);
    });
  }, [pipeline, fmJobs]);

  const majorJobs = jobs.filter(j => j.bu === "major");

  // CRM helpers
  const getCompanyContacts  = (cid) => contacts.filter(p => p.companyId === cid);
  const getCompanyJobs      = (cid) => jobs.filter(j => j.companyId === cid);
  const getCompanyPipeline  = (cid) => pipeline.filter(o => o.companyId === cid);
  const getCompanyTotalValue = (cid) => jobs.filter(j => j.companyId === cid).reduce((s, j) => s + j.contractValue, 0);
  const getCompanySites     = (cid) => sites.filter(s => s.companyId === cid);

  // ── Supabase: load data on mount ──────────────────────────
  useEffect(() => {
    // Safety: always show app after 8s even if DB hangs
    const timeout = setTimeout(() => { setSupaReady(true); setDbError("Connection timed out."); }, 8000);
    const load = async () => {
      setDbLoading(l => ({ ...l, companies: true, sites: true, lawnSites: true, subcontractors: true }));
      try {
        const [coRes, siteRes, subRes, fmRes, teamRes, crmRes, ctRes, mpPipeRes, mpRes, mpwRes, mpVendorRes, mpEstimateRes] = await Promise.all([
          supa.from("companies").select("*"),
          fetch(`${SUPA_URL}/rest/v1/sites?select=*&limit=1000`, {
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
          }).then(r => r.json()).then(data => ({ data, error: null })).catch(error => ({ data: null, error })),
          fetch(`${SUPA_URL}/rest/v1/subcontractors?select=*&limit=2000`, {
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
          }).then(r => r.json()).then(data => ({ data, error: null })).catch(error => ({ data: null, error })),
          supa.from("fm_jobs").select("*"),
          supa.from("fm_team").select("*"),
          supa.from("crm_contacts").select("*"),
          fetch(`${SUPA_URL}/rest/v1/contacts?select=id,company_id,first_name,last_name,title,email,phone&limit=1000`, {
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
          }).then(r => r.json()).then(data => ({ data, error: null })).catch(error => ({ data: null, error })),
          fetch(`${SUPA_URL}/rest/v1/mp_pipeline?select=*&limit=500`, {
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
          }).then(r => r.json()).then(data => ({ data, error: null })).catch(() => ({ data: null, error: null })),
          fetch(`${SUPA_URL}/rest/v1/mp_jobs?select=*&limit=100`, {
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
          }).then(r => r.json()).then(data => ({ data, error: null })).catch(() => ({ data: null, error: null })),
          fetch(`${SUPA_URL}/rest/v1/mp_weekly_reports?select=*&limit=1000`, {
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
          }).then(r => r.json()).then(data => ({ data, error: null })).catch(() => ({ data: null, error: null })),
          fetch(`${SUPA_URL}/rest/v1/mp_bid_vendors?select=*&limit=500&order=company.asc`, {
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
          }).then(r => r.json()).then(data => ({ data, error: null })).catch(() => ({ data: null, error: null })),
          fetch(`${SUPA_URL}/rest/v1/mp_estimates?select=*&limit=500`, {
            headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}` }
          }).then(r => r.json()).then(data => ({ data, error: null })).catch(() => ({ data: null, error: null })),
        ]);
        if (coRes.data?.length)   setCompanies(coRes.data.map(dbToCompany));
        if (siteRes.data?.length) setSites(siteRes.data.map(dbToSite));
        if (subRes.data?.length)  setSubcontractors(subRes.data.map(dbToSub));
        if (fmRes.data?.length)   setFmJobs(fmRes.data.map(dbToFmJob));
        if (teamRes.data?.length) setFmTeam(teamRes.data.map(dbToTeamMember));
        if (crmRes.data?.length)  setCrmContacts(crmRes.data.map(dbToCrmContact));
        if (Array.isArray(mpPipeRes.data) && mpPipeRes.data.length) {
          const pipeLoaded = mpPipeRes.data.map(r => ({
            id: r.id, name: r.name||"", companyId: r.company_id||"", contactName: r.contact_name||"",
            value: r.value||0, stage: r.stage||"budgeting_lead",
            // notes may be plain text OR JSON (oppDetails stored as JSON)
            notes: (() => { try { const p=JSON.parse(r.notes||""); return typeof p==="object"?"":r.notes||""; } catch(e){ return r.notes||""; } })(),
            bu: "major", closeDate: r.close_date||"", nextSteps: [],
            pipelineType: "budgeting", budgetDueDate: "", bidDueDate: "", dbId: r.id,
            city: r.city||"", state: r.state||"", address: r.address||""
          }));
          setPipeline(prev => {
            const existing = prev.filter(p => p.bu !== "major");
            return [...existing, ...pipeLoaded];
          });
          // Parse oppDetails from notes JSON where present
          const detailsFromDB = {};
          mpPipeRes.data.forEach(r => {
            if (!r.notes) return;
            try {
              const parsed = JSON.parse(r.notes);
              if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
                detailsFromDB[r.id] = parsed;
              }
            } catch(e) {}
          });
          if (Object.keys(detailsFromDB).length > 0) {
            setOppDetails(prev => ({...detailsFromDB, ...prev})); // existing in-memory takes precedence
          }
        }
        let loadedMpJobs = [];
        if (Array.isArray(mpRes.data) && mpRes.data.length) {
          try {
            loadedMpJobs = mpRes.data.map(dbToMpJob);
            setMpJobs(loadedMpJobs);
          } catch(e) { console.warn("mpJobs map error:", e); }
        }

        // Auto-sync: any pipeline opp with stage "won" or "closed_won" that has no mp_job → create one
        if (Array.isArray(mpPipeRes.data)) {
          const wonPipeOpps = mpPipeRes.data.filter(r => r.stage === "won" || r.stage === "Won" || r.stage === "closed_won");
          const existingJobNames = new Set(loadedMpJobs.map(j => j.name));
          const existingJobIds   = new Set(loadedMpJobs.map(j => j.id));
          const toCreate = wonPipeOpps.filter(r => !existingJobNames.has(r.name||"") && !existingJobIds.has(r.id));
          if (toCreate.length > 0) {
            const synced = toCreate.map(r => ({
              id: r.id, name: r.name||"", client: "", status: "active",
              contractValue: r.value||0, startDate: "", endDate: "",
              pm: "", pct: 0, daysAhead: null, completionSchedule: "",
              changeOrderStatus: "", budgetStatus: "", billingStatus: "",
              gpm: 0, longLeadItems: "", km1: "", km1Date: "", km2: "",
              km2Date: "", km3: "", km3Date: "", notes: r.notes||"", amountBilled: 0,
              companyId: r.company_id||"",
            }));
            setMpJobs(prev => {
              const existingIds = new Set(prev.map(j=>j.id));
              return [...prev, ...synced.filter(j=>!existingIds.has(j.id))];
            });
            // Also persist to Supabase
            synced.forEach(j => {
              try {
                fetch(`${SUPA_URL}/rest/v1/mp_jobs`, {
                  method: "POST",
                  headers: { apikey: SUPA_KEY, Authorization: `Bearer ${SUPA_KEY}`, "Content-Type": "application/json", Prefer: "return=minimal,resolution=ignore-duplicates" },
                  body: JSON.stringify({ id: j.id, name: j.name, client: j.client, status: "active", contract_value: j.contractValue||null, notes: j.notes||null, company_id: j.companyId||null })
                });
              } catch(e) {}
            });
          }
        }
        if (Array.isArray(mpwRes.data) && mpwRes.data.length) setMpWeeklyReports(mpwRes.data.map(dbToMpWeekly));
        if (Array.isArray(mpVendorRes.data) && mpVendorRes.data.length) setMpVendorDB(mpVendorRes.data.map(dbToMpVendor));
        if (Array.isArray(mpEstimateRes.data) && mpEstimateRes.data.length) {
          const newWbs = {}, newBids = {}, newPhase = {};
          mpEstimateRes.data.forEach(row => {
            if (!row.opp_id || !row.wbs_data) return;
            try {
              const parsed = JSON.parse(row.wbs_data);
              if (parsed.wbs)   newWbs[row.opp_id]   = parsed.wbs;
              if (parsed.bids)  newBids[row.opp_id]  = parsed.bids;
              if (parsed.phase) newPhase[row.opp_id] = parsed.phase;
            } catch(e) {}
          });
          if (Object.keys(newWbs).length)   setWbsData(newWbs);
          if (Object.keys(newBids).length)  setBidPackages(newBids);
          if (Object.keys(newPhase).length) setEstimatePhase(newPhase);
        }
        // contacts table — deduplicate by name+company before setting
        if (Array.isArray(ctRes.data) && ctRes.data.length) {
          const seen = new Set();
          const deduped = ctRes.data.filter(r => {
            const key = (r.first_name+r.last_name+r.company_id).toLowerCase();
            if (seen.has(key)) return false;
            seen.add(key); return true;
          });
          setContacts(deduped.map(dbToContact));
        }
        setSupaReady(true);
      } catch(e) {
        setDbError("Could not connect to database.");
        setSupaReady(true); // Always show the app even if DB fails
      }
      setDbLoading(l => ({ ...l, companies: false, sites: false, lawnSites: false, subcontractors: false }));
      clearTimeout(timeout);
    };
    load();
  }, []);

  // Site helpers
  const openAddSite = () => { setEditSiteId(null); setSiteForm({ companyId: "", contactIds: [], storeNumber: "", address: "", phone: "", accessCode: "", notes: "" }); setShowSiteForm(true); };
  const openEditSite = (s) => { setEditSiteId(s.id); setSiteForm({ ...s }); setShowSiteForm(true); };
  const saveSite = async () => {
    if (!siteForm.storeNumber.trim() && !siteForm.address.trim()) return;
    const entry = { ...siteForm, lat: parseFloat(siteForm.lat)||null, lng: parseFloat(siteForm.lng)||null };
    if (editSiteId) {
      const updated = { ...entry, id: editSiteId };
      setSites(sites.map(s => s.id === editSiteId ? updated : s));
      supa.from("sites").update(siteToDB(updated)).eq("id", editSiteId);
    } else {
      const newId = "s" + Date.now();
      const newEntry = { ...entry, id: newId };
      setSites(s => [...s, newEntry]);
      supa.from("sites").insert(siteToDB(newEntry));
    }
    setShowSiteForm(false);
  };
  const deleteSite = async (id) => { setSites(sites.filter(s => s.id !== id)); setSelectedSite(null); supa.from("sites").delete().eq("id", id); };

  const geocodeAllSites = async (siteList) => {
    const ungeocoded = siteList.filter(s => !s.lat || !s.lng);
    if (!ungeocoded.length) return;
    setGeocodeAllProgress({ done: 0, total: ungeocoded.length });
    for (let i = 0; i < ungeocoded.length; i++) {
      const site = ungeocoded[i];
      if (!site.address) continue;
      try {
        const res = await fetch("https://nominatim.openstreetmap.org/search?format=json&limit=1&q=" + encodeURIComponent(site.address));
        const geo = await res.json();
        if (geo[0]) {
          const lat = parseFloat(geo[0].lat);
          const lng = parseFloat(geo[0].lon);
          setSites(prev => prev.map(s => s.id === site.id ? { ...s, lat, lng } : s));
          await supa.from("sites").update({ lat, lng }).eq("id", site.id);
        }
      } catch(e) {}
      setGeocodeAllProgress({ done: i + 1, total: ungeocoded.length });
      await new Promise(r => setTimeout(r, 1100)); // Nominatim rate limit: 1 req/sec
    }
    setGeocodeAllProgress(null);
  };
  const toggleSiteContact = (contactId) => {
    const ids = siteForm.contactIds || [];
    setSiteForm(f => ({ ...f, contactIds: ids.includes(contactId) ? ids.filter(i => i !== contactId) : [...ids, contactId] }));
  };

  // Lawn/Snow site helpers
  const openAddLsSite  = () => { setEditLsSiteId(null); setLsSiteForm({ companyId: "", storeNumber: "", address: "", phone: "", accessCode: "", notes: "", lat: "", lng: "" }); setShowLsSiteForm(true); };
  const openEditLsSite = (s) => { setEditLsSiteId(s.id); setLsSiteForm({ ...s, lat: String(s.lat || ""), lng: String(s.lng || "") }); setShowLsSiteForm(true); };
  const saveLsSite = async () => {
    if (!lsSiteForm.address.trim() && !lsSiteForm.storeNumber.trim()) return;
    const buTag = activeBU; // "lawn" or "snow"
    const entry = { ...lsSiteForm, lat: parseFloat(lsSiteForm.lat)||null, lng: parseFloat(lsSiteForm.lng)||null };
    if (editLsSiteId) {
      const existing = sites.find(s => s.id === editLsSiteId) || {};
      const bus = existing.businessUnits || [];
      const updated = { ...existing, ...entry, id: editLsSiteId, businessUnits: bus.includes(buTag) ? bus : [...bus, buTag] };
      setSites(sites.map(s => s.id === editLsSiteId ? updated : s));
      supa.from("sites").update(siteToDB(updated)).eq("id", editLsSiteId);
    } else {
      const newId = (activeBU === "lawn" ? "ln" : "sn") + Date.now();
      const newEntry = { ...entry, id: newId, contactIds: [], businessUnits: [buTag] };
      setSites(s => [...s, newEntry]);
      supa.from("sites").insert(siteToDB(newEntry));
    }
    setShowLsSiteForm(false);
  };
  const deleteLsSite = async (id) => {
    setSites(sites.filter(s => s.id !== id));
    setSelectedLsSite(null);
    supa.from("sites").delete().eq("id", id);
  };

  // Company color map for pins
  const companyColorMap = useMemo(() => {
    const map = {};
    companies.forEach((c, i) => { map[c.id] = PIN_COLORS[i % PIN_COLORS.length]; });
    return map;
  }, [companies]);

  // CapEx job helpers
  const openAddCapex = () => { setEditCapexId(null); setCapexForm({ name: "", companyId: "", siteId: "", approverContactId: "", contractValue: "", stage: "estimating", startDate: "", endDate: "", pm: "", pct: 0, bidDueDate: "", followUpDate: "", buyoutDate: "", invoiceDate: "", notes: "" }); setShowCapexForm(true); };
  const openEditCapex = (j) => { setEditCapexId(j.id); setCapexForm({ ...j, contractValue: String(j.contractValue) }); setShowCapexForm(true); };
  // ── CapEx trigger logic ────────────────────────────────────
  const fireCapexTrigger = (job, newStage) => {
    const patch = {};
    // Trigger 1: moved to owner_approval → auto-set follow-up date 3 days out
    if (newStage === "owner_approval" && !job.followUpDate) {
      patch.followUpDate = new Date(Date.now() + 3*86400000).toISOString().slice(0,10);
    }
    // Trigger 2: moved to buyout (Won) → set buyout date prompt (auto-flag)
    if (newStage === "buyout" && !job.buyoutDate) {
      patch.buyoutDate = ""; // signals Brad to fill in
    }
    // Trigger 3: moved to bill (100% complete) → flag for Noah satisfaction review
    if (newStage === "bill") {
      patch.satisfactionReviewDue = true;
    }
    return patch;
  };

  const updateCapexJobPersist = (id, patch) => {
    setCapexJobs(prev => prev.map(j => {
      if (j.id !== id) return j;
      const updated = { ...j, ...patch };
      try {
        const dbRow = {
          id: updated.id, name: updated.name||"", company_id: updated.companyId||null,
          site_id: updated.siteId||null, contract_value: updated.contractValue||0,
          gross_profit: updated.grossProfit||0, stage: updated.stage||"estimating",
          start_date: updated.startDate||null, end_date: updated.endDate||null,
          pm: updated.pm||"", pct: updated.pct||0,
          bid_due_date: updated.bidDueDate||null, follow_up_date: updated.followUpDate||null,
          buyout_date: updated.buyoutDate||null, invoice_date: updated.invoiceDate||null,
          notes: updated.notes||"", store_code: updated.storeCode||"",
          approver_contact_id: updated.approverContactId||null,
          noah_approved: updated.noahApproved||false,
          brad_approved: updated.bradApproved||false,
          won_date: updated.wonDate||null,
          lost_date: updated.lostDate||null,
          sub_cost: updated.subCost||null,
          owner_cost: updated.ownerCost||null,
          proposal_number: updated.proposalNumber||null,
          brad_reviewed: updated.bradReviewed||false,
          assigned_to: updated.assignedTo||null,
        };
        supa.from("capex_jobs").update(dbRow).eq("id", id);
      } catch(e) {}
      return updated;
    }));
  };

  const saveCapex = () => {
    if (!capexForm.name.trim()) return;
    const entry = { ...capexForm, contractValue: Number(capexForm.contractValue), pct: Number(capexForm.pct || 0) };
    if (editCapexId) {
      const existing = capexJobs.find(j => j.id === editCapexId) || {};
      const updated = { ...entry, id: editCapexId };
      // Fire triggers if stage changed
      if (existing.stage !== updated.stage) {
        const triggerPatch = fireCapexTrigger(existing, updated.stage);
        Object.assign(updated, triggerPatch);
      }
      setCapexJobs(capexJobs.map(j => j.id === editCapexId ? updated : j));
      try { supa.from("capex_jobs").update({ stage: updated.stage, name: updated.name, contract_value: updated.contractValue, pm: updated.pm, pct: updated.pct, follow_up_date: updated.followUpDate||null, buyout_date: updated.buyoutDate||null, invoice_date: updated.invoiceDate||null, notes: updated.notes||"" }).eq("id", editCapexId); } catch(e) {}
    } else {
      const newId = "cx" + Date.now();
      const newJob = { ...entry, id: newId };
      setCapexJobs([...capexJobs, newJob]);
      try { supa.from("capex_jobs").insert({ id: newId, name: newJob.name, company_id: newJob.companyId||null, site_id: newJob.siteId||null, contract_value: newJob.contractValue||0, stage: newJob.stage||"estimating", pm: newJob.pm||"", pct: 0, notes: newJob.notes||"" }); } catch(e) {}
    }
    autoTagCrmContacts(capexForm.companyId, "CapEx");
    setShowCapexForm(false);
  };
  const deleteCapex = (id) => { setCapexJobs(capexJobs.filter(j => j.id !== id)); setSelectedCapexJob(null); try { supa.from("capex_jobs").delete().eq("id", id); } catch(e) {} };
  const moveCapexStage = (id, dir) => {
    setCapexJobs(capexJobs.map(j => {
      if (j.id !== id) return j;
      const idx = CAPEX_FM_STAGES.findIndex(s => s.id === j.stage);
      const newStage = CAPEX_FM_STAGES[Math.max(0, Math.min(CAPEX_FM_STAGES.length - 1, idx + dir))].id;
      const triggerPatch = newStage !== j.stage ? fireCapexTrigger(j, newStage) : {};
      const updated = { ...j, stage: newStage, ...triggerPatch };
      try { supa.from("capex_jobs").update({ stage: newStage, ...Object.fromEntries(Object.entries(triggerPatch).map(([k,v]) => [k.replace(/([A-Z])/g, '_$1').toLowerCase(), v])) }).eq("id", id); } catch(e) {}
      return updated;
    }));
  };

  // ── Auto-tag CRM contacts when a job is created/updated ──
  const autoTagCrmContacts = (companyId, division) => {
    if (!companyId) return;
    setCrmContacts(prev => prev.map(c => {
      if (c.companyId !== companyId) return c;
      const divs = c.divisions || [];
      if (divs.includes(division)) return c; // already tagged
      const updated = { ...c, divisions: [...divs, division] };
      try { supa.from("crm_contacts").update({ divisions: updated.divisions }).eq("id", c.id); } catch(e) {}
      return updated;
    }));
  };

    // FM job helpers
  const openAddFm = () => { setEditFmId(null); setFmForm({ name: "", companyId: "", siteId: "", approverContactId: "", contractValue: "", grossProfit: "", stage: "estimating", startDate: "", endDate: "", pm: "", pct: 0, bidDueDate: "", quoteDueDate: "", proposalDate: "", followUpDate: "", buyoutDate: "", invoiceDate: "", notes: "", storeCode: "", projectNo: "", ownersProjectNo: "", vendorInvoiceAmount: "", vendorInvoiceNumber: "", subcontractorId: "", vendorNextStep: "", vendorQuotePrice: "", vendorQuoteScope: "", scopeOfWork: "", coordinator: "" }); setFmCompanySearch(""); setFmSiteSearch(""); setShowFmForm(true); };
  const openEditFm = (j) => { setEditFmId(j.id); setFmForm({ ...j, contractValue: String(j.contractValue) }); setFmCompanySearch(""); setFmSiteSearch(""); setShowFmForm(true); };
